constexpr size_t STATIC_CHUNK_SIZE = 4096;

template <typename Element, size_t compute_iterations>
__global__ void bench_block_kernel(Element* data, Element* sums, size_t num_chunks) {
  size_t chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;

  if (chunk_idx >= num_chunks) return;

  Element sum = 0;
  size_t start_idx = chunk_idx * STATIC_CHUNK_SIZE;
  size_t end_idx = start_idx + STATIC_CHUNK_SIZE;

  Element f = data[start_idx];

  for (size_t i = start_idx; i < end_idx; i++) {
    Element t = data[i];
    for (size_t j = 0; j < compute_iterations; j++) {
      t = t * t + f;
    }
    sum += t;
  }

  sums[chunk_idx] = sum;
}

template <typename Element>
__global__ void reduce_sum_kernel(Element* sums, Element* result, size_t num_chunks) {
  Element sum = 0;

  for (size_t i = 0; i < num_chunks; i++) {
    sum += sums[i];
  }

  if (threadIdx.x == 0 && blockIdx.x == 0) {
    *result = sum;
  }
}

template <typename Element, size_t compute_iterations>
cudaError_t bench(size_t len, const Element seed1, const Element seed2, 
                  Element* host_src, Element* host_result, size_t size_bytes) {
  Element* device_src;
  Element* device_sums;
  Element* device_result;

  size_t num_chunks = (len + STATIC_CHUNK_SIZE - 1) / STATIC_CHUNK_SIZE;

  cudaMalloc(&device_src, size_bytes);
  cudaMalloc(&device_sums, num_chunks * sizeof(Element));
  cudaMalloc(&device_result, sizeof(Element));

  cudaMemcpy(device_src, host_src, size_bytes, cudaMemcpyHostToDevice);

  int threads_per_block = 256;
  int blocks = (num_chunks + threads_per_block - 1) / threads_per_block;

  bench_block_kernel<Element, compute_iterations>(device_src, device_sums, num_chunks);

  reduce_sum_kernel<Element>(device_sums, device_result, num_chunks);

  cudaMemcpy(host_result, device_result, sizeof(Element), cudaMemcpyDeviceToHost);

  cudaFree(device_src);
  cudaFree(device_sums);
  cudaFree(device_result);

  return cudaSuccess;
}

