  for (size_t chunk = 0; chunk < num_chunks; chunk++) {
    bench_block_kernel<Element, compute_iterations, static_chunk_size>(src_d, sum_d, chunk * static_chunk_size);
    Element partial_sum;
    cudaMemcpy(&partial_sum, sum_d, sizeof(Element), cudaMemcpyDeviceToHost);
