  int* c_int = (int*)c;
  size_t num_ints = size / sizeof(int);
  int* c_int_d;
  cudaMalloc(&c_int_d, num_ints * sizeof(int));

  cudaMemset(c_int_d, 0, num_ints * sizeof(int));
  cudaMemcpy(c_int, c_int_d, num_ints * sizeof(int), cudaMemcpyDeviceToHost);
